const AUTHOR_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['dir', 'ok', 'docsBytes', 'codeLines', 'svgWritten', 'summary'],
  properties: {
    dir: { type: 'string' },
    ok: { type: 'boolean', description: 'true if all three files were written' },
    docsBytes: { type: 'number' },
    codeLines: { type: 'number' },
    svgWritten: { type: 'boolean' },
    summary: { type: 'string', description: 'one-line description of what was authored' },
  },
}

const VERIFY_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['dir', 'pass', 'issues'],
  properties: {
    dir: { type: 'string' },
    pass: { type: 'boolean' },
    issues: { type: 'array', items: { type: 'string' } },
  },
}

function authorPrompt(it) {
  const abs = `${ROOT}/${it.dir}`
  const src = it.chapterPath
    ? `Source textbook chapter: ${ROOT}/${it.chapterPath}${it.section ? ` (focus on section ${it.section} — grep the chapter for that section heading and read a ~300-line window around it)` : ' (skim for the relevant subsection by topic)'}.`
    : `This is a lab/capstone lesson with no single textbook section — author it from established networking knowledge and the lesson title/phase.`
  return `You are authoring ONE lesson of an open-source Computer Networks course so it matches the DEPTH of a reference AI-engineering course. Output must be genuine, specific, technically correct networking content — NOT generic filler.

LESSON
- Title: ${it.title}
- Folder (absolute): ${abs}
- Phase: ${it.phase}
- Type: ${it.type || 'Learn'} | Languages: ${it.langs || 'Python, Wireshark, diagrams'}
- ${src}

STEP 1 — Read context (cheap):
1. Read ${abs}/docs/en.md (the current shallow template) to get the exact topic and source pointer. You will REPLACE it.
2. Read the reference exemplar for the quality bar (structure, specificity, tables, decision-logic): ${REF_EXEMPLAR}
3. If a source chapter is given above, grep+read just the relevant section for accurate facts. Do NOT paste raw OCR text — write clean prose.

STEP 2 — Write THREE files (use the Write tool; parent dirs already exist):

A) ${abs}/docs/en.md  — 9,000–14,000 bytes of REAL content, this exact section order:
   - '# <Title>'
   - A '> ' blockquote summary (4–8 sentences) packed with concrete, correct specifics: real protocol field names, sizes, timers, algorithm names, RFC numbers, failure modes.
   - Metadata lines: '**Type:** …', '**Languages:** …', '**Prerequisites:** …', '**Time:** ~N minutes'
   - '## Learning Objectives' (4–6 specific, testable bullets)
   - '## The Problem' (a concrete real-world scenario/symptom an engineer faces)
   - '## The Concept' with 4–8 '### ' subsections containing real mechanism detail: tables, packet/frame field layouts, state transitions, decision rules, worked numeric examples. Reference 'code/main.py' and the SVG ('assets/${it.svgName}') where they illustrate a point.
   - '## Build It' (concrete steps tied to the code)
   - '## Use It' (a table: Task | Evidence | What Good Looks Like)
   - '## Ship It' (points to outputs/, the artifact)
   - '## Exercises' (4–6 SPECIFIC scenario exercises, not generic)
   - '## Key Terms' (table: Term | What people say | What it actually means — REAL terms from this lesson, real distinctions)
   - '## Further Reading' (real RFCs/standards/books with correct numbers, e.g. 'RFC 791', 'IEEE 802.3', Tanenbaum chapter)
   ABSOLUTELY FORBIDDEN strings: "AI Engineering", "keeps the … course rhythm", "A chapter topic to memorize", "<!-- Page", "replace with the", "Section X.Y.Z". No raw OCR fragments, no page numbers.

B) ${abs}/code/main.py — a REAL, runnable, stdlib-only Python program (NO pip deps, NO network calls) directly tied to this lesson: e.g. a protocol/field parser, frame/packet builder, checksum/CRC calculator, subnet calculator, sliding-window or CSMA/ALOHA simulator, routing-table/Dijkstra solver, DNS/HTTP message parser, cipher/HMAC demo — whatever fits THIS topic. 120–220 lines. Must include a module docstring, well-named functions, type hints, and a 'def main():' that runs a realistic demonstration with printed output, guarded by 'if __name__ == "__main__":'. It MUST execute without error under plain 'python3 main.py'.

C) ${abs}/assets/${it.svgName} — a clean, standalone, valid SVG diagram that genuinely illustrates THIS lesson's mechanism (packet format, state machine, topology, timing diagram, or flow). Requirements: '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 W H" width="W" height="H">', readable on a cream (#FFF7EC) background, use ink #2A1A2E for text/strokes and berry #E2557A for accents/highlights, system font-family (e.g. 'Inter, sans-serif' / 'monospace'), real labels, ~3,000–6,000 bytes. No external images/fonts, no <script>.

Return the structured status object. Keep docs >= 9000 bytes; if shorter, expand the Concept section with more real detail before finishing.`
}

function verifyPrompt(it) {
  const abs = `${ROOT}/${it.dir}`
  return `Adversarially verify ONE authored networking lesson at ${abs}. Read these three files: docs/en.md, code/main.py, and assets/${it.svgName}.

FAIL (pass=false) and list each issue if ANY of:
- docs/en.md < 9000 bytes, or missing any required section (Learning Objectives, The Problem, The Concept with >=4 '### ' subsections, Build It, Use It, Ship It, Exercises, Key Terms, Further Reading).
- docs contains any forbidden leftover: "AI Engineering", "course rhythm", "A chapter topic to memorize", "<!-- Page", "replace with the", a literal "Section X.Y.Z", or raw OCR fragments / stray page numbers.
- docs content is generic/vague rather than specific and technically correct for "${it.title}" (check a few facts: field names, RFC numbers, sizes, timers must be plausible and correct).
- code/main.py is still the stub (contains "replace with the"), is < 100 lines, imports non-stdlib packages, makes network calls, or would not run (no main(), syntax issues). Use Bash to run: python3 -m py_compile "${abs}/code/main.py" and report failure.
- assets/${it.svgName} is missing, malformed (no <svg ... viewBox), or empty/generic.

Return {dir, pass, issues}. Be strict — this must reach the depth of a professionally authored course.`
}

const results = await pipeline(
  WORKLIST,
  (it) => agent(authorPrompt(it), { label: `author:${it.dir.split('/').pop()}`, phase: 'Author', schema: AUTHOR_SCHEMA, agentType: 'general-purpose' }),
  (authored, it) => agent(verifyPrompt(it), { label: `verify:${it.dir.split('/').pop()}`, phase: 'Verify', schema: VERIFY_SCHEMA, agentType: 'general-purpose' })
    .then((v) => ({ ...(v || { dir: it.dir, pass: false, issues: ['verify agent died'] }), authored }))
)

const clean = results.filter(Boolean)
const passed = clean.filter((r) => r.pass)
const failed = clean.filter((r) => !r.pass)
log(`Done: ${passed.length} passed, ${failed.length} failed, ${WORKLIST.length - clean.length} dropped`)

return {
  total: WORKLIST.length,
  passed: passed.length,
  failed: failed.map((f) => ({ dir: f.dir, issues: f.issues })),
}
